      font-display: swap;
    }

    :root {
      --bg: #f4efe7;
      --panel: #fffaf2;
      --ink: #152127;
      --muted: #5f6b70;
      --line: rgba(21, 33, 39, 0.12);
      --orange: #d96b2b;
      --teal: #1f7a78;
      --blue: #2f5fe3;
      --gold: #b78912;
      --mint: #dcefe8;
      --sand: #f4e2c8;
      --sky: #dce7ff;
      --rose: #f6ddd5;
      --shadow: 0 18px 45px rgba(21, 33, 39, 0.08);
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      background:
        radial-gradient(circle at top left, rgba(217, 107, 43, 0.08), transparent 28%),
        radial-gradient(circle at top right, rgba(47, 95, 227, 0.08), transparent 25%),
        linear-gradient(180deg, #f7f2eb 0%, var(--bg) 100%);
      color: var(--ink);
      font-family: "OpenFons Sans", "Noto Sans SC", "PingFang SC", "Microsoft YaHei", "Segoe UI", sans-serif;
      line-height: 1.6;
    }

    .page {
      width: min(1360px, calc(100vw - 32px));
      margin: 0 auto;
      padding: 32px 0 72px;
    }

    .hero {
      display: grid;
      grid-template-columns: 1.2fr 0.8fr;
      gap: 24px;
      align-items: stretch;
      margin-bottom: 28px;
    }

    .hero-main,
    .hero-side,
    .section,
    .project-card,
    .flow-card,
    .matrix-card,
    .fusion-card,
    .phase-card {
      background: rgba(255, 250, 242, 0.92);
      border: 1px solid var(--line);
      border-radius: 24px;
      box-shadow: var(--shadow);
      backdrop-filter: blur(10px);
    }

    .hero-main {
      padding: 30px 30px 26px;
      position: relative;
      overflow: hidden;
    }

    .hero-main::after {
      content: "";
      position: absolute;
      inset: auto -50px -50px auto;
      width: 200px;
      height: 200px;
      background: radial-gradient(circle, rgba(217, 107, 43, 0.16), transparent 68%);
