    .eyebrow {
      display: inline-flex;
      align-items: center;
      gap: 10px;
      padding: 8px 12px;
      border-radius: 999px;
      background: rgba(21, 33, 39, 0.05);
      color: var(--muted);
      font-size: 13px;
      letter-spacing: 0.05em;
      text-transform: uppercase;
